function generateRandomString(length = 20) {
  const chars = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
  let result = '';
  for (let i = 0; i < length; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
}

// Prefix that always appears at the start
const prefix = '<YOUR_PREFIX_HERE>';

// Generate token with prefix
const token = prefix + generateRandomString(20); // You can change 20 to increase/decrease randomness length

// Get data from previous nodes
const senderId = $('When Executed by Another Workflow').first().json.SenderId;
const email = $('Email Verification').first().json.email;
const name = $('Email Verification').first().json.Name;

return [
  {
    json: {
      token,
      senderId,
      email,
      name
    }
  }
];

// Example input (replace or map dynamically)
const email = $input.first().json["Email"];
const Name = $input.first().json["Name"];
const SenderId = $input.first().json["Sender Id"];

// 1️⃣ Basic email format regex (generic)
const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// Check if the email is formatted correctly
if (!regex.test(email)) {
  return [{
    SenderId,
    Name,
    email,
    valid: false,
    reason: "Invalid email format"
  }];
}

// 2️⃣ Extract domain
const domain = email.split("@")[1];

// 3️⃣ Check if it's a Gmail address (auto valid)
if (domain.toLowerCase() === "gmail.com") {
  return [{
    SenderId,
    Name,
    email,
    valid: true,
    reason: "Valid Gmail address"
  }];
}

// 4️⃣ For custom domains: verify MX records using Google DNS API
const url = `https://dns.google/resolve?name=${domain}&type=MX`;

async function httpGet(url) {
  const options = {
    method: "GET",
    url: url,
  };
  return await this.helpers.httpRequest(options);
}

try {
  const data = await httpGet.call(this, url);

  if (data.Answer && data.Answer.length > 0) {
    return [{
      SenderId,
      Name,
      email,
      valid: true,
      reason: "Valid business email (domain has MX records)"
    }];
  } else {
    return [{
      SenderId,
      Name,
      email,
      valid: false,
      reason: "Invalid domain (no MX records found)"
    }];
  }
} catch (err) {
  return [{
    SenderId,
    Name,
    email,
    valid: false,
    reason: "Lookup failed: " + err.message
  }];
}

